--- c2s
---
--- 英雄召唤
---@param refId string 召唤表refId
---@param count number 召唤次数
---@param useDiamond boolean 使用钻石召唤
---@param useDiamond boolean 是否自动遣返3星英雄
function LxHeroCallHandler:HeroCallReq(refId, count, useDiamond)
    local autoSacrifice = false
    if LxPlayerPrefs.autosacrifice == "true" then
        autoSacrifice = true
    end
    useDiamond = useDiamond or false
    local proto = LxProtoHelper.CreateProto(LxProtoIds.HeroCallReq)
    proto.refId = refId
    proto.count = count
    proto.useDiamond = useDiamond
    proto.autoSacrifice = autoSacrifice
    SendMessage(LxProtoIds.HeroCallReq, proto)
end

--- 设置心愿英雄
---@param refId number 召唤表refId
---@param wish number[]
function LxHeroCallHandler:SetWishHeroReq(refId,wishHeroRefIds)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.SetWishHeroReq)
    proto.refId = refId
    local wish = proto.wish
    for i,v in ipairs(wishHeroRefIds) do
        wish:append(v)
    end
    SendMessage(LxProtoIds.SetWishHeroReq, proto)
end

--- 查看日志
---@param refId number 召唤表refId
function LxHeroCallHandler:HeroCallLogReq(refId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.HeroCallLogReq)
    --proto.refId = refId
    for i,v in ipairs(refId) do
        proto.refId:append(v)
    end
    SendMessage(LxProtoIds.HeroCallLogReq, proto)
end
