--- s2c
---
function LxHeroCallHandler:OnHeroCallResp(pb)
    local callRefId
    if pb.callInfo then
        ModuleCenter.HeroCall:SetHeroCallInfo(pb.callInfo)
        callRefId = pb.callInfo.refId
        FireEvent(EventNames.HEROCALL_CALLRESULT)
    end
    local thingsInfo
    if pb.thingsInfo then
        ---@type LxThingsInfo 获得的奖励
        thingsInfo = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
        local func = function()
            CtrlCenter.HeroCall:OpenHeroCallResult(thingsInfo,callRefId,{
                rankValue = pb.rankValue,cross = pb.cross,
            })
        end
        local skipAni = false
        if callRefId == HeroCall_RefIds.Common or callRefId == HeroCall_RefIds.Higher then
            skipAni = CtrlCenter.HeroCall:GetHeroCallJumpAniState()
        elseif callRefId == HeroCall_RefIds.Integral then
            skipAni = true
        else
            skipAni = CtrlCenter.HeroCall:GetRaceCallJumpAniState()
        end

        if skipAni then
            func()
        else
            ShowPanel(UiNames.CallHeroAnim, {refId = callRefId, closeCallBack = func})
        end
    end
    FireEvent(EventNames.HEROCALL_REWARD, callRefId, thingsInfo)

    FireEvent(EventNames.HERO_INFO_CHANGE)

    CtrlCenter.City:RefreshCallHeroTipsInfo()
end

function LxHeroCallHandler:OnSetWishHeroResp(pb)
    local refId = pb.refId
    if pb.callInfo then
        ModuleCenter.HeroCall:SetHeroCallInfo(pb.callInfo)
        FireEvent(EventNames.HEROCALL_CALLRESULT)
    end
end

function LxHeroCallHandler:OnHeroCallLogResp(pb)
end

return LxHeroCallHandler